const { SQSClient, SendMessageBatchCommand, ReceiveMessageCommand } = require("@aws-sdk/client-sqs");
const { DynamoDBClient, PutItemCommand } = require("@aws-sdk/client-dynamodb");

const sqs = new SQSClient({ region: "us-west-2" });
const dynamoDb = new DynamoDBClient({ region: "us-west-2" });

const queueUrl = "https://sqs.us-west-2.amazonaws.com/123456789012/YourQueueName";

const run = async () => {
  const params = {
    QueueUrl: queueUrl,
    MaxNumberOfMessages: 10,
    MessageAttributeNames: ["All"],
    WaitTimeSeconds: 20,
    VisibilityTimeout: 300 // Adjust as needed
  };

  const { Contents } = await sqs.send(new ReceiveMessageCommand(params));

  for (const message of Contents) {
    const transactionData = JSON.parse(message.Body);

    try {
      await processTransaction(transactionData);
      await deleteMessage(queueUrl, message.ReceiptHandle);
    } catch (error) {
      console.error(`Error processing transaction: ${error}`);
    }
  }
};

const processTransaction = async (data) => {
  // Execute your database update operations here based on the message content.
  const params = {
    TableName: "YourDynamoDBTable",
    Item: data
  };

  await dynamoDb.send(new PutItemCommand(params));
};

const deleteMessage = async (queueUrl, receiptHandle) => {
  const params = {
    QueueUrl: queueUrl,
    ReceiptHandle: receiptHandle
  };

  return sqs.send(new DeleteMessageCommand(params));
};

run();